from dataclasses import dataclass
from enum import IntEnum
import requests

class Severity(IntEnum):
    P0 = 0
    P1 = 1
    P2 = 2
    P3 = 3
    P4 = 4

PROM_URL = "http://prometheus.internal:9090"

def _query(q: str) -> float:
    resp = requests.get(f"{PROM_URL}/api/v1/query", params={"query": q}, timeout=5)
    resp.raise_for_status()
    result = resp.json()["data"]["result"]
    return float(result[0]["value"][1]) if result else 0.0

@dataclass
class SeveritySignals:
    error_rate_pct:      float
    latency_ratio:       float
    customer_scope_pct:  float
    safety_violation:    bool
    privacy_incident:    bool

def gather_signals() -> SeveritySignals:
    return SeveritySignals(
        error_rate_pct=_query(
            "sum(rate(claude_api_requests_total{status=~'5..'}[5m]))"
            " / sum(rate(claude_api_requests_total[5m])) * 100"
        ),
        latency_ratio=_query(
            "histogram_quantile(0.50, rate(claude_request_duration_seconds_bucket[5m]))"
            " / clamp_min(claude_latency_baseline_p50, 0.001)"
        ),
        customer_scope_pct=_query(
            "count(count by (org_id)(claude_api_errors_total > 0))"
            " / count(count by (org_id)(claude_api_requests_total)) * 100"
        ),
        safety_violation=False,
        privacy_incident=False,
    )

def assess_severity(s: SeveritySignals) -> Severity:
    if s.safety_violation or s.privacy_incident:
        return Severity.P0

    candidates = [Severity.P4]

    if s.error_rate_pct > 25:      candidates.append(Severity.P0)
    elif s.error_rate_pct > 5:     candidates.append(Severity.P1)
    elif s.error_rate_pct > 1:     candidates.append(Severity.P2)
    elif s.error_rate_pct > 0.1:   candidates.append(Severity.P3)

    if s.latency_ratio > 5:        candidates.append(Severity.P0)
    elif s.latency_ratio > 2:      candidates.append(Severity.P1)
    elif s.latency_ratio > 1.5:    candidates.append(Severity.P2)
    elif s.latency_ratio > 1.1:    candidates.append(Severity.P3)

    if s.customer_scope_pct > 20:  candidates.append(Severity.P0)
    elif s.customer_scope_pct > 5: candidates.append(Severity.P1)
    elif s.customer_scope_pct > 1: candidates.append(Severity.P2)
    elif s.customer_scope_pct > 0: candidates.append(Severity.P3)

    return min(candidates)

import anthropic, statistics

EVAL_SYSTEM = """
You are a completion quality judge. Given a user prompt and an AI response,
score the response 1-10 for coherence and factual plausibility.
Return ONLY the integer score on a single line.
"""

def score_completion(prompt: str, response: str) -> int:
    client = anthropic.Anthropic()
    result = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=10,
        system=EVAL_SYSTEM,
        messages=[{"role": "user", "content": f"Prompt: {prompt}

Response: {response}"}],
    )
    return int(result.content[0].text.strip())

def rolling_quality_score(samples: list[tuple[str, str]]) -> float:
    """Return mean quality score for a batch of (prompt, response) pairs."""
    scores = [score_completion(p, r) for p, r in samples[:20]]  # cap at 20
    return statistics.mean(scores)
